        const totalH = data.canvas.h;
        const fitScale = Math.min(rect.width / totalW, rect.height / totalH) * 1.06;
        const offsetX = (rect.width - totalW * fitScale) / 2;
        const offsetY = (rect.height - totalH * fitScale) / 2;
